class Solution:
    def bestClosingTime(self, customers):
        n = len(customers)
        best_j = 0
        best_pen = None
        for j in range(n + 1):
            pen = 0
            for i in range(j):
                if customers[i] == 'N':
                    pen += 1
            for i in range(j, n):
                if customers[i] == 'Y':
                    pen += 1
            if best_pen is None or pen < best_pen:
                best_pen = pen
                best_j = j
        return best_j

