class Solution:
    def bestClosingTime(self, customers):
        pen = customers.count('Y')
        best_pen = pen
        best_j = 0
        for i, ch in enumerate(customers):
            if ch == 'Y':
                pen -= 1
            else:
                pen += 1
            if pen < best_pen:
                best_pen = pen
                best_j = i + 1
        return best_j

