var bestClosingTime = function(customers) {
    let pen = 0;
    for (const c of customers) if (c === 'Y') pen++;
    let bestPen = pen, bestJ = 0;
    for (let i = 0; i < customers.length; i++) {
        if (customers[i] === 'Y') pen--; else pen++;
        if (pen < bestPen) { bestPen = pen; bestJ = i + 1; }
    }
    return bestJ;
};
